def find_max_alternating_subarray(nums):
    max_len = -1
    n = len(nums)

    for i in range(n):
        for j in range(i + 1, n):
            current_len = j - i + 1
            if current_len < 2:
                continue

            is_alternating = True
            for k in range(1, current_len):
                expected_diff = (-1) ** (k + 1)
                actual_diff = nums[i + k] - nums[i + k - 1]
                if actual_diff != expected_diff:
                    is_alternating = False
                    break

            if is_alternating:
                if current_len > max_len:
                    max_len = current_len

    return max_len
